import React, { useState, useEffect } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';

// Mock de dados para visualização
const baseCategoryData = [
  { name: 'Infraestrutura', value: 4500, color: '#f97316' }, // Orange
  { name: 'Operacional', value: 3000, color: '#1e293b' }, // Blackish
  { name: 'Marketing', value: 2000, color: '#94a3b8' }, // Slate
  { name: 'Pessoal', value: 5000, color: '#fb923c' }, // Lighter Orange
];

// Cores para o modo de alto contraste
const highContrastColors = ['#000000', '#ffffff', '#ffff00', '#0000ff'];

const annualHistory = [
  { month: 'Junho', income: 60000, expense: 40000 },
  { month: 'Maio', income: 55000, expense: 42000 },
  { month: 'Abril', income: 50000, expense: 44000 },
  { month: 'Março', income: 45000, expense: 46000 },
  { month: 'Fevereiro', income: 42000, expense: 38000 },
  { month: 'Janeiro', income: 40000, expense: 35000 },
];

interface ReportsPageProps {
  onLoadAction: 'print' | null;
  onActionComplete: () => void;
}

export const ReportsPage: React.FC<ReportsPageProps> = ({ onLoadAction, onActionComplete }) => {
  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isExportingPDF, setIsExportingPDF] = useState(false);
  const [isHighContrast, setIsHighContrast] = useState(false);

  useEffect(() => {
    if (onLoadAction === 'print') {
      handleExportPDF();
      onActionComplete();
    }
  }, [onLoadAction]);

  const categoryData = baseCategoryData.map((item, index) => ({
    ...item,
    color: isHighContrast ? highContrastColors[index % highContrastColors.length] : item.color
  }));

  const fetchExportDataFromBackend = async () => {
    return new Promise((resolve) => {
      setTimeout(() => {
        const fullData = annualHistory.map(item => ({
          ...item,
          balance: item.income - item.expense,
          status: 'FECHADO',
          date: `01/2024`
        }));
        resolve(fullData);
      }, 1200);
    });
  };

  const handleExportCSV = async () => {
    try {
      setIsExportingCSV(true);
      const data: any = await fetchExportDataFromBackend();
      const headers = ['Mês', 'Receitas (MZN)', 'Despesas (MZN)', 'Saldo Líquido (MZN)', 'Status de Fechamento'];
      const rows = data.map((item: any) => [
        item.month,
        item.income.toFixed(2),
        item.expense.toFixed(2),
        item.balance.toFixed(2),
        item.status
      ]);

      const csvContent = [headers.join(';'), ...rows.map((row: any) => row.join(';'))].join('\n');
      const BOM = '\uFEFF';
      const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `FINTECH_Relatorio_Financeiro_${new Date().getTime()}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error(error);
    } finally {
      setIsExportingCSV(false);
    }
  };

  const handleExportPDF = () => {
    setIsExportingPDF(true);
    setTimeout(() => {
      window.print();
      setIsExportingPDF(false);
    }, 300);
  };

  const totalValue = categoryData.reduce((acc, curr) => acc + curr.value, 0);

  return (
    <article className={`space-y-8 animate-fadeIn pb-20 ${isHighContrast ? 'bg-white text-black' : ''}`} aria-labelledby="report-title">
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 no-print">
        <div>
          <h2 id="report-title" className="text-3xl font-black text-slate-900 tracking-tight">Inteligência de Dados</h2>
          <p className="text-slate-500 font-medium">Exporte relatórios consolidados para apresentações ou auditoria.</p>
        </div>
