      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 print-container">
        <section 
          className={`lg:col-span-2 p-10 rounded-[40px] shadow-sm border flex flex-col items-center chart-container ${isHighContrast ? 'bg-white border-black' : 'bg-white border-slate-100'}`}
          aria-labelledby="chart-analysis-title"
