          <h3 id="chart-analysis-title" className="text-lg font-black text-slate-900 tracking-tight mb-8 self-start">Análise de Gastos por Categoria</h3>
          <div className="h-80 w-full" role="img" aria-label={`Gráfico de pizza mostrando a distribuição de gastos. Total de ${totalValue} MZN.`}>
