              <div className="pt-6 border-t border-slate-100 mt-6">
                 <div className={`flex justify-between items-center p-5 rounded-3xl border ${isHighContrast ? 'bg-black text-white border-black' : 'bg-slate-50 text-slate-900 border-slate-100'}`}>
                    <span className={`text-xs font-black uppercase ${isHighContrast ? 'text-white/70' : 'text-slate-400'}`}>Total Acumulado</span>
                    <span className="text-2xl font-black">{totalValue.toLocaleString('pt-MZ')} MZN</span>
