  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isPrinting, setIsPrinting] = useState(false);
  const [isHighContrast, setIsHighContrast] = useState(false);

  useEffect(() => {
    if (onLoadAction === 'print') {
      handleExportPDF();
    }
  }, [onLoadAction]);

  const categoryData = baseCategoryData.map((item, index) => ({
    ...item,
    color: isHighContrast ? highContrastColors[index % highContrastColors.length] : item.color
  }));

  const handleExportCSV = async () => {
    try {
      setIsExportingCSV(true);
      const csvData = annualHistory.map(item => [
        item.month,
        item.income.toFixed(2),
        item.expense.toFixed(2),
        (item.income - item.expense).toFixed(2),
        'FECHADO'
      ]);

      const headers = ['Mês', 'Receitas (MZN)', 'Despesas (MZN)', 'Saldo Líquido (MZN)', 'Status'];
      const csvContent = [headers.join(';'), ...csvData.map(row => row.join(';'))].join('\n');
      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `FINTECH_Financeiro_${new Date().toLocaleDateString()}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error(error);
    } finally {
      setIsExportingCSV(false);
