import React, { useState, useEffect } from 'react';
import { PaymentProvider } from '../types';

interface MobileMoneyModalProps {
  isOpen: boolean;
  onClose: () => void;
  amount: number;
  description: string;
  onSuccess: (provider: PaymentProvider, number: string) => void;
}

export const MobileMoneyModal: React.FC<MobileMoneyModalProps> = ({ isOpen, onClose, amount, description, onSuccess }) => {
  const [phoneNumber, setPhoneNumber] = useState('');
  const [step, setStep] = useState<'INPUT' | 'PROCESSING' | 'SUCCESS'>('INPUT');
  const [provider, setProvider] = useState<PaymentProvider | null>(null);

  // Detectar operadora pelo prefixo
  useEffect(() => {
    const cleanNum = phoneNumber.replace(/\s/g, '');
    if (cleanNum.startsWith('84') || cleanNum.startsWith('85')) {
      setProvider('M-PESA');
    } else if (cleanNum.startsWith('86') || cleanNum.startsWith('87')) {
      setProvider('E-MOLA');
    } else {
      setProvider(null);
    }
  }, [phoneNumber]);

  if (!isOpen) return null;

  const handleProcess = () => {
    if (!provider || phoneNumber.length < 9) return;

    setStep('PROCESSING');

    // Simulação do tempo de resposta do Gateway de Pagamento (STK Push)
    setTimeout(() => {
      setStep('SUCCESS');
      setTimeout(() => {
        onSuccess(provider, phoneNumber);
        handleClose();
      }, 2000);
    }, 4000);
  };

  const handleClose = () => {
    setStep('INPUT');
    setPhoneNumber('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-md animate-fadeIn">
      <div className="bg-white rounded-[40px] w-full max-w-md shadow-2xl overflow-hidden animate-scaleIn">

        {step === 'INPUT' && (
          <div className="p-8 space-y-6">
            <div className="text-center">
              <div className="inline-flex p-4 bg-slate-50 rounded-3xl mb-4 border border-slate-100">
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-slate-400"><rect width="14" height="20" x="5" y="2" rx="2" ry="2"/><path d="M12 18h.01"/></svg>
              </div>
              <h3 className="text-xl font-black text-slate-900">Mobile Money Checkout</h3>
              <p className="text-sm text-slate-500 font-medium">Insira o número para iniciar o STK Push</p>
            </div>

            <div className="p-5 bg-slate-50 rounded-3xl border border-slate-100 flex justify-between items-center">
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor a Pagar</p>
                <p className="text-xl font-black text-slate-900">{amount.toLocaleString('pt-MZ')} <span className="text-xs text-slate-400">MZN</span></p>
              </div>
              <div className="text-right">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Serviço</p>
                <p className="text-sm font-bold text-slate-700 truncate max-w-[120px]">{description}</p>
              </div>
            </div>

            <div className="space-y-4">
              <div className="relative">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Número de Telefone (+258)</label>
                <input 
                  type="tel" 
                  maxLength={9}
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value.replace(/\D/g, ''))}
                  placeholder="84XXXXXXX"
                  className="w-full px-6 py-5 bg-white border-2 border-slate-100 rounded-3xl text-2xl font-black tracking-widest outline-none focus:border-orange-500 transition-all text-center"
                />

                {/* Indicador de Operadora Dinâmico */}
                <div className="absolute right-4 top-[48px] transition-all">
                  {provider === 'M-PESA' && (
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-rose-600 rounded-xl text-white animate-fadeIn">
                       <span className="text-[9px] font-black uppercase">M-Pesa</span>
                    </div>
                  )}
                  {provider === 'E-MOLA' && (
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-orange-500 rounded-xl text-white animate-fadeIn">
                       <span className="text-[9px] font-black uppercase">e-Mola</span>
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="flex gap-3">
              <button onClick={handleClose} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-[24px] font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">Cancelar</button>
              <button 
                onClick={handleProcess}
                disabled={!provider || phoneNumber.length < 9}
                className="flex-[2] py-5 bg-slate-900 text-white rounded-[24px] font-black text-xs uppercase tracking-widest transition-all shadow-xl shadow-slate-900/20 active:scale-95 disabled:opacity-30"
              >
                Solicitar Pagamento
              </button>
            </div>
          </div>
        )}

        {step === 'PROCESSING' && (
          <div className="p-12 text-center space-y-8 animate-fadeIn">
            <div className="relative inline-block">
              <div className="w-24 h-24 border-4 border-slate-100 border-t-orange-500 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-slate-200"><path d="m12 14 4-4"/><path d="m3.34 19 1.4-1.4"/><path d="D19.07 4.93l-1.4 1.4"/><path d="M12 2v2"/><path d="m4.93 19.07 1.4-1.4"/><path d="M2 12h2"/><path d="m19.07 19.07-1.4-1.4"/><path d="M12 22v-2"/><path d="m4.93 4.93 1.4 1.4"/><path d="M20 12h2"/><path d="m12 14 4-4"/></svg>
              </div>
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-900 mb-2">Aguardando PIN...</h3>
              <p className="text-slate-500 font-medium">Verifique o seu telemóvel <strong>{phoneNumber}</strong> e introduza o seu código secreto para autorizar a transação.</p>
            </div>
            <div className="p-4 bg-orange-50 rounded-2xl border border-orange-100">
               <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest">Status da Operadora</p>
               <p className="text-xs font-bold text-slate-600 mt-1">STK Push enviado com sucesso via {provider}</p>
            </div>
          </div>
        )}

        {step === 'SUCCESS' && (
          <div className="p-12 text-center space-y-6 animate-scaleIn">
            <div className="w-24 h-24 bg-emerald-500 rounded-full flex items-center justify-center mx-auto shadow-xl shadow-emerald-500/20">
              <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" className="text-white"><polyline points="20 6 9 17 4 12"/></svg>
            </div>
            <div>
              <h3 className="text-3xl font-black text-slate-900 mb-2">Pago com Sucesso!</h3>
              <p className="text-slate-500 font-medium">A transação foi confirmada e os fundos foram processados via {provider}.</p>
            </div>
            <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">Ref: {Math.random().toString(36).substring(7).toUpperCase()}</p>
          </div>
        )}

      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus, PaymentProvider } from '../types';
import { CategoryManagerModal } from './CategoryManagerModal';
import { MobileMoneyModal } from './MobileMoneyModal';

const STORAGE_KEY = 'fintech_transactions_v1';
const CATEGORIES_STORAGE_KEY = 'fintech_categories_v1';

interface TransactionsPageProps {
  mode: AccountType;
  isModalOpen: boolean;
  onModalClose: () => void;
  onModalOpen: () => void;
  initialTransactionType: TransactionType | null;
}

export const TransactionsPage: React.FC<TransactionsPageProps> = ({ mode, isModalOpen, onModalClose, onModalOpen, initialTransactionType }) => {
  const [showFilters, setShowFilters] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  const [isMobileMoneyModalOpen, setIsMobileMoneyModalOpen] = useState(false);
  const [selectedTransaction, setSelectedTransaction] = useState<Transaction | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  // Search & Filter States
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<TransactionStatus | 'ALL'>('ALL');

  // Form States for New/Edit Transaction
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<string>('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formNotes, setFormNotes] = useState('');
  const [formPaymentMethod, setFormPaymentMethod] = useState<PaymentProvider>('CASH');

  // Categories State with Persistence
  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem(CATEGORIES_STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Erro ao carregar categorias", e);
      }
    }
    return [
      { id: '1', name: 'Salário', icon: '💰', color: 'bg-emerald-500', type: 'INCOME' },
      { id: '2', name: 'Vendas', icon: '🛒', color: 'bg-emerald-500', type: 'INCOME' },
      { id: '3', name: 'Aluguel', icon: '🏠', color: 'bg-rose-500', type: 'EXPENSE' },
      { id: '4', name: 'Alimentação', icon: '🍔', color: 'bg-rose-500', type: 'EXPENSE' },
      { id: '5', name: 'Transporte', icon: '🚗', color: 'bg-rose-500', type: 'EXPENSE' },
      { id: '6', name: 'Metas', icon: '🎯', color: 'bg-blue-500', type: 'EXPENSE' },
    ];
  });

  // Sync Categories to localStorage
  useEffect(() => {
    localStorage.setItem(CATEGORIES_STORAGE_KEY, JSON.stringify(categories));
  }, [categories]);

  // Initial State with Persistence Logic
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Erro ao carregar dados do localStorage", e);
      }
    }
    return [
      { id: '1', amount: 4500, description: 'Venda de Produto A', date: '2024-05-20', type: 'INCOME', status: 'COMPLETED', categoryId: '2', tenantId: 't1', notes: 'Venda direta para cliente regular.', paymentMethod: 'M-PESA' },
      { id: '2', amount: 1200, description: 'Fornecedor de Embalagens', date: '2024-05-19', type: 'EXPENSE', status: 'PENDING', categoryId: '4', tenantId: 't1', paymentMethod: 'CASH' },
      { id: '3', amount: 35000, description: 'Aluguel Escritório', date: '2024-05-15', type: 'EXPENSE', status: 'COMPLETED', categoryId: '3', tenantId: 't1', paymentMethod: 'BANK_TRANSFER' },
      { id: '4', amount: 15000, description: 'Consultoria Mensal', date: '2024-05-10', type: 'INCOME', status: 'OVERDUE', categoryId: '2', tenantId: 't1', notes: 'Aguardando confirmação de transferência internacional.' },
    ];
  });

  // Effect to sync transactions to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(transactions));
    if (selectedTransaction) {
      const updated = transactions.find(t => t.id === selectedTransaction.id);
      if (updated) setSelectedTransaction(updated);
    }
  }, [transactions]);

  useEffect(() => {
    if (isModalOpen && initialTransactionType) {
      setFormType(initialTransactionType);
    }
  }, [isModalOpen, initialTransactionType]);

  // Derived filtered transactions
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'ALL' || t.status === filterStatus;
      const tDate = new Date(t.date).setHours(0,0,0,0);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate).setHours(0,0,0,0);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate).setHours(0,0,0,0);
      return matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  // Export CSV Function
  const handleExportCSV = () => {
    try {
      setIsExporting(true);
      const headers = ['Data', 'Descricao', 'Categoria', 'Tipo', 'Valor (MZN)', 'Status', 'Metodo', 'Notas'];

      const rows = filteredTransactions.map(t => {
        const categoryName = categories.find(c => c.id === t.categoryId)?.name || 'Outros';
        const typeLabel = t.type === 'INCOME' ? 'Entrada' : 'Saida';
        const statusLabel = t.status === 'COMPLETED' ? 'Efetivado' : t.status === 'PENDING' ? 'Pendente' : 'Atrasado';

        return [
          t.date,
          `"${t.description.replace(/"/g, '""')}"`, 
          categoryName,
          typeLabel,
          t.amount.toFixed(2).replace('.', ','), 
          statusLabel,
          t.paymentMethod || 'Não especificado',
          `"${(t.notes || '').replace(/"/g, '""')}"`
        ];
      });

      const csvContent = [
        headers.join(';'),
        ...rows.map(row => row.join(';'))
      ].join('\n');

      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      const dateStr = new Date().toISOString().split('T')[0];

      link.setAttribute('href', url);
      link.setAttribute('download', `FINTECH_Extrato_${dateStr}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error("Falha ao exportar CSV:", error);
    } finally {
      setIsExporting(false);
    }
  };

  const totals = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === 'INCOME') {
        acc.income += curr.amount;
      } else {
        acc.expense += curr.amount;
      }
      return acc;
    }, { income: 0, expense: 0 });
  }, [filteredTransactions]);

  const balance = totals.income - totals.expense;

  const closeAndResetModal = () => {
    onModalClose();
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormDate(new Date().toISOString().split('T')[0]);
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
    setFormNotes('');
    setFormPaymentMethod('CASH');
  };

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) {
      alert('Por favor, preencha todos os campos obrigatórios.');
      return;
    }

    const transactionData: Transaction = {
      id: editingTransaction?.id || Math.random().toString(36).substr(2, 9),
      amount: parseFloat(formAmount),
      description: formDescription,
      date: formDate,
      type: formType,
      status: formStatus,
      categoryId: formCategoryId,
      tenantId: 't1',
      notes: formNotes,
      paymentMethod: formPaymentMethod,
    };

    if (editingTransaction) {
      setTransactions(transactions.map(t => t.id === editingTransaction.id ? transactionData : t));
    } else {
      setTransactions([transactionData, ...transactions]);
    }

    closeAndResetModal();
  };

  const handleMobileMoneySuccess = (provider: PaymentProvider, number: string) => {
    if (selectedTransaction) {
      setTransactions(transactions.map(t => 
        t.id === selectedTransaction.id 
          ? { ...t, status: 'COMPLETED', paymentMethod: provider, mobileNumber: number, providerRef: Math.random().toString(36).substring(7).toUpperCase() } 
          : t
      ));
    }
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount.toString());
    setFormDate(t.date);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormNotes(t.notes || '');
    setFormPaymentMethod(t.paymentMethod || 'CASH');
    onModalOpen();
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este lançamento?')) {
      setTransactions(transactions.filter(t => t.id !== id));
      if (selectedTransaction?.id === id) setSelectedTransaction(null);
    }
  };

  const toggleTransactionStatus = (id: string) => {
    setTransactions(transactions.map(t => {
      if (t.id === id) {
        const nextStatus: TransactionStatus = t.status === 'COMPLETED' ? 'PENDING' : 'COMPLETED';
        return { ...t, status: nextStatus };
      }
      return t;
    }));
