                   {selectedTransaction.type === 'INCOME' ? '+' : '-'} {selectedTransaction.amount.toLocaleString('pt-MZ')}
                   <span className="text-xl ml-2 opacity-50 font-bold uppercase tracking-tighter">MZN</span>
                </p>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                  {selectedTransaction.type === 'INCOME' ? 'Entrada Registrada' : 'Saída Registrada'}
                </p>
              </div>

              {/* Botão de Pagamento Mobile (Apenas se pendente) */}
              {selectedTransaction.status === 'PENDING' && (
                <div className="p-1 bg-slate-900 rounded-[32px]">
                   <button 
                    onClick={() => setIsMobileMoneyModalOpen(true)}
                    className="w-full flex items-center justify-center gap-3 py-4 bg-orange-500 hover:bg-orange-600 text-white rounded-[28px] font-black text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95"
                   >
                     <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="20" x="5" y="2" rx="2" ry="2"/><path d="M12 18h.01"/><path d="m9 12 2 2 4-4"/></svg>
                     Pagar via Mobile Money
                   </button>
                </div>
              )}

              {/* Badges & Category */}
              <div className="grid grid-cols-2 gap-4">
                <div className="p-5 bg-slate-50 rounded-[24px] border border-slate-100 flex flex-col items-center text-center">
                   <span className="text-[9px] font-black text-slate-400 uppercase mb-3">Status Atual</span>
                   {getStatusBadge(selectedTransaction, true)}
                </div>
                <div className="p-5 bg-slate-50 rounded-[24px] border border-slate-100 flex flex-col items-center text-center">
                   <span className="text-[9px] font-black text-slate-400 uppercase mb-3">Categoria</span>
                   <div className="flex items-center gap-2">
                      <span className="text-xl">{categories.find(c => c.id === selectedTransaction.categoryId)?.icon}</span>
                      <span className="text-sm font-black text-slate-900">{categories.find(c => c.id === selectedTransaction.categoryId)?.name}</span>
                   </div>
                </div>
              </div>

              {/* Main Info */}
              <div className="space-y-6">
                <div>
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Descrição</label>
                   <p className="text-lg font-bold text-slate-900 leading-tight">{selectedTransaction.description}</p>
                </div>
                <div>
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Data do Lançamento</label>
                   <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" x2="16" y1="2" y2="6"/><line x1="8" x2="8" y1="2" y2="6"/><line x1="3" x2="21" y1="10" y2="10"/></svg>
                      </div>
                      <p className="text-sm font-black text-slate-700">
                        {new Date(selectedTransaction.date).toLocaleDateString('pt-MZ', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric' })}
                      </p>
                   </div>
                </div>

                {/* Mobile Money Info if exists */}
                {(selectedTransaction.paymentMethod === 'M-PESA' || selectedTransaction.paymentMethod === 'E-MOLA') && (
                  <div className={`p-6 rounded-[32px] border ${selectedTransaction.paymentMethod === 'M-PESA' ? 'bg-rose-50 border-rose-100 text-rose-800' : 'bg-orange-50 border-orange-100 text-orange-800'}`}>
                    <label className="text-[10px] font-black uppercase tracking-widest block mb-3 opacity-60">Dados do Pagamento Móvel</label>
                    <div className="space-y-2">
                      <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold uppercase">Operadora</span>
                        <span className="text-xs font-black">{selectedTransaction.paymentMethod}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold uppercase">Número</span>
                        <span className="text-xs font-black">{selectedTransaction.mobileNumber || 'Não registrado'}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold uppercase">Referência</span>
                        <span className="text-xs font-mono font-black">{selectedTransaction.providerRef || '---'}</span>
                      </div>
                    </div>
                  </div>
                )}

                {/* Notes Section */}
                <div className="p-6 bg-slate-50 rounded-[32px] border border-slate-100">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-3">Observações Adicionais</label>
                   <p className="text-sm font-medium text-slate-600 italic leading-relaxed">
                      {selectedTransaction.notes || "Nenhuma observação registrada para este lançamento."}
                   </p>
                </div>
              </div>
            </div>

            {/* Drawer Actions */}
            <div className="p-8 border-t border-slate-100 grid grid-cols-2 gap-4">
              <button 
                onClick={() => deleteTransaction(selectedTransaction.id)}
                className="py-4 bg-rose-50 text-rose-500 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-rose-100 transition-all flex items-center justify-center gap-2"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                Excluir
              </button>
              <button 
                onClick={() => startEditTransaction(selectedTransaction)}
                className="py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-black transition-all flex items-center justify-center gap-2 shadow-lg shadow-slate-900/20"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"/></svg>
                Editar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* CATEGORY MANAGER MODAL */}
      <CategoryManagerModal 
        isOpen={isCategoryModalOpen} 
        onClose={() => setIsCategoryModalOpen(false)} 
        categories={categories}
        setCategories={setCategories}
      />

      {/* MOBILE MONEY MODAL */}
      <MobileMoneyModal 
        isOpen={isMobileMoneyModalOpen}
        onClose={() => setIsMobileMoneyModalOpen(false)}
        amount={selectedTransaction?.amount || 0}
        description={selectedTransaction?.description || ''}
        onSuccess={handleMobileMoneySuccess}
      />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus, PaymentProvider } from '../types';
import { CategoryManagerModal } from './CategoryManagerModal';
import { MobileMoneyModal } from './MobileMoneyModal';
import { ReceiptTemplate } from './ReceiptTemplate';

const STORAGE_KEY = 'fintech_transactions_v1';
const CATEGORIES_STORAGE_KEY = 'fintech_categories_v1';

interface TransactionsPageProps {
  mode: AccountType;
  isModalOpen: boolean;
  onModalClose: () => void;
  onModalOpen: () => void;
  initialTransactionType: TransactionType | null;
}

export const TransactionsPage: React.FC<TransactionsPageProps> = ({ mode, isModalOpen, onModalClose, onModalOpen, initialTransactionType }) => {
  const [showFilters, setShowFilters] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  const [isMobileMoneyModalOpen, setIsMobileMoneyModalOpen] = useState(false);
  const [selectedTransaction, setSelectedTransaction] = useState<Transaction | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isPrintingReceipt, setIsPrintingReceipt] = useState(false);

  // Search & Filter States
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<TransactionStatus | 'ALL'>('ALL');

  // Form States for New/Edit Transaction
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<string>('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formNotes, setFormNotes] = useState('');
  const [formPaymentMethod, setFormPaymentMethod] = useState<PaymentProvider>('CASH');

  // Categories State
  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem(CATEGORIES_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  // Transactions State
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(transactions));
    if (selectedTransaction) {
      const updated = transactions.find(t => t.id === selectedTransaction.id);
      if (updated) setSelectedTransaction(updated);
    }
  }, [transactions]);

  const handlePrintReceipt = () => {
    setIsPrintingReceipt(true);
    // Pequeno delay para garantir que o componente de recibo seja renderizado antes de chamar window.print()
    setTimeout(() => {
      window.print();
      setIsPrintingReceipt(false);
    }, 500);
  };

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'ALL' || t.status === filterStatus;
      const tDate = new Date(t.date).setHours(0,0,0,0);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate).setHours(0,0,0,0);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate).setHours(0,0,0,0);
      return matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  const handleExportCSV = () => {
    try {
      setIsExporting(true);
      const headers = ['Data', 'Descricao', 'Categoria', 'Tipo', 'Valor (MZN)', 'Status', 'Metodo', 'Notas'];
      const rows = filteredTransactions.map(t => {
        const categoryName = categories.find(c => c.id === t.categoryId)?.name || 'Outros';
        return [t.date, `"${t.description}"`, categoryName, t.type, t.amount.toFixed(2), t.status, t.paymentMethod, `"${t.notes || ''}"`];
      });
      const csvContent = [headers.join(';'), ...rows.map(row => row.join(';'))].join('\n');
      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `FINTECH_Extrato.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } finally {
      setIsExporting(false);
    }
  };

  const totals = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === 'INCOME') acc.income += curr.amount;
      else acc.expense += curr.amount;
      return acc;
    }, { income: 0, expense: 0 });
  }, [filteredTransactions]);

  const balance = totals.income - totals.expense;

  const closeAndResetModal = () => {
    onModalClose();
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormDate(new Date().toISOString().split('T')[0]);
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
    setFormNotes('');
    setFormPaymentMethod('CASH');
  };

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) {
      alert('Preencha os campos obrigatórios.');
      return;
    }
    const transactionData: Transaction = {
      id: editingTransaction?.id || Math.random().toString(36).substr(2, 9),
      amount: parseFloat(formAmount),
      description: formDescription,
      date: formDate,
      type: formType,
      status: formStatus,
      categoryId: formCategoryId,
      tenantId: 't1',
      notes: formNotes,
      paymentMethod: formPaymentMethod,
    };
    if (editingTransaction) setTransactions(transactions.map(t => t.id === editingTransaction.id ? transactionData : t));
    else setTransactions([transactionData, ...transactions]);
    closeAndResetModal();
  };

  const handleMobileMoneySuccess = (provider: PaymentProvider, number: string) => {
    if (selectedTransaction) {
      setTransactions(transactions.map(t => 
        t.id === selectedTransaction.id 
          ? { ...t, status: 'COMPLETED', paymentMethod: provider, mobileNumber: number, providerRef: Math.random().toString(36).substring(7).toUpperCase() } 
          : t
      ));
    }
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount.toString());
    setFormDate(t.date);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormNotes(t.notes || '');
    setFormPaymentMethod(t.paymentMethod || 'CASH');
    onModalOpen();
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Eliminar este lançamento?')) {
      setTransactions(transactions.filter(t => t.id !== id));
      if (selectedTransaction?.id === id) setSelectedTransaction(null);
    }
  };

  const getStatusBadge = (t: Transaction, isLarge = false) => {
    const status = t.status;
    let colorClass = status === 'COMPLETED' ? "bg-emerald-50 text-emerald-600 border-emerald-100" : status === 'PENDING' ? "bg-amber-50 text-amber-600 border-amber-100" : "bg-rose-50 text-rose-600 border-rose-100";
    let label = status === 'COMPLETED' ? "Efetivado" : status === 'PENDING' ? "Pendente" : "Atrasado";
    return <span className={`${isLarge ? 'px-4 py-2 text-[12px]' : 'px-3 py-1.5 text-[10px]'} rounded-full font-black border uppercase ${colorClass}`}>{label}</span>;
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20 relative">
      {/* Receipt Template (Hidden by default, visible only on print) */}
      {selectedTransaction && (
        <ReceiptTemplate 
          transaction={selectedTransaction} 
          category={categories.find(c => c.id === selectedTransaction.categoryId)}
          tenantName="FINTECH SaaS Moçambique" 
        />
      )}

      {/* Main UI */}
      <div className="no-print">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex-1 max-w-2xl w-full">
            <div className="flex items-center gap-3">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registos..."
                  className="w-full pl-12 pr-6 py-4 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-orange-500/10 focus:border-orange-500 transition-all font-medium text-slate-700 shadow-sm"
                />
              </div>
              <button onClick={() => setShowFilters(!showFilters)} className={`p-4 rounded-[22px] border ${showFilters ? 'bg-orange-500 text-white border-orange-500' : 'bg-white border-slate-200 text-slate-500'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="21" x2="4" y1="4" y2="4"/><line x1="21" x2="4" y1="12" y2="12"/><line x1="21" x2="4" y1="20" y2="20"/><circle cx="7" cy="4" r="2"/><circle cx="17" cy="12" r="2"/><circle cx="7" cy="20" r="2"/></svg>
              </button>
            </div>
          </div>

          <div className="flex gap-3 w-full lg:w-auto">
            <button onClick={handleExportCSV} disabled={isExporting} className="px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-[22px] font-black text-xs uppercase tracking-widest flex items-center gap-2">CSV</button>
            <button onClick={onModalOpen} className="flex-1 lg:flex-none bg-orange-500 text-white px-8 py-4 rounded-[22px] font-black text-xs uppercase tracking-widest shadow-lg shadow-orange-500/20 active:scale-95 transition-all">Novo Lançamento</button>
          </div>
        </div>

        {showFilters && (
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-xl grid grid-cols-1 md:grid-cols-3 gap-6 animate-slideDown mt-6">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Status</label>
              <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value as any)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none">
                <option value="ALL">Todos os Status</option>
                <option value="COMPLETED">Efetivado</option>
                <option value="PENDING">Pendente</option>
                <option value="OVERDUE">Atrasado</option>
              </select>
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Início</label>
              <input type="date" value={filterStartDate} onChange={(e) => setFilterStartDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Fim</label>
              <input type="date" value={filterEndDate} onChange={(e) => setFilterEndDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
            </div>
          </div>
        )}

        <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden mt-8">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Valor</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredTransactions.map((t) => (
                  <tr key={t.id} onClick={() => setSelectedTransaction(t)} className={`cursor-pointer transition-colors group ${selectedTransaction?.id === t.id ? 'bg-orange-50/50' : 'hover:bg-slate-50/50'}`}>
                    <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(t.date).toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' })}</td>
                    <td className="px-8 py-6"><p className="text-sm font-black text-slate-900">{t.description}</p></td>
                    <td className="px-8 py-6"><span className="px-3 py-1.5 rounded-xl text-xs font-black bg-slate-100 text-slate-700">{categories.find(c => c.id === t.categoryId)?.name || 'Outros'}</span></td>
                    <td className="px-8 py-6">{getStatusBadge(t)}</td>
                    <td className={`px-8 py-6 text-base font-black text-right ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>{t.amount.toLocaleString('pt-MZ')} MZN</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="bg-slate-950 p-8 flex flex-col md:flex-row items-center justify-between gap-8">
            <div className="flex items-center gap-12">
               <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Entradas</span><span className="text-xl font-black text-white">{totals.income.toLocaleString()} MZN</span></div>
               <div className="flex flex-col"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Saídas</span><span className="text-xl font-black text-white">{totals.expense.toLocaleString()} MZN</span></div>
            </div>
            <div className={`p-6 rounded-[32px] border-2 flex flex-col items-end min-w-[200px] ${balance >= 0 ? 'bg-orange-500 border-orange-400 text-white' : 'bg-white text-slate-900 border-slate-200'}`}>
              <span className="text-[10px] font-black uppercase tracking-widest mb-1">Saldo Líquido</span>
              <span className="text-3xl font-black">{balance.toLocaleString()} MZN</span>
            </div>
          </div>
        </div>
      </div>

      {/* Detail Drawer */}
      {selectedTransaction && (
        <div className="fixed inset-0 z-[90] flex justify-end bg-slate-950/40 backdrop-blur-[2px] animate-fadeIn no-print" onClick={() => setSelectedTransaction(null)}>
          <div className="w-full max-w-md bg-white h-full shadow-2xl animate-slideLeft flex flex-col" onClick={(e) => e.stopPropagation()}>
            <div className="p-8 border-b border-slate-100 flex items-center justify-between">
              <div><h3 className="text-xl font-black text-slate-900">Detalhes do Lançamento</h3><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">#{selectedTransaction.id}</p></div>
              <button onClick={() => setSelectedTransaction(null)} className="p-3 hover:bg-slate-50 rounded-2xl transition-all border border-slate-100"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="text-center">
                <p className={`text-5xl font-black ${selectedTransaction.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>{selectedTransaction.amount.toLocaleString('pt-MZ')} MZN</p>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">{selectedTransaction.type === 'INCOME' ? 'Receita Recebida' : 'Despesa Registrada'}</p>
              </div>

              {selectedTransaction.type === 'INCOME' && (
                <button 
                  onClick={handlePrintReceipt}
                  className="w-full py-4 bg-slate-900 text-white rounded-[24px] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl hover:bg-black transition-all active:scale-95"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
                  Imprimir Recibo (PDF)
                </button>
              )}

              <div className="space-y-4">
                 <div className="p-5 bg-slate-50 rounded-3xl border border-slate-100"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Descrição</label><p className="font-bold text-slate-900">{selectedTransaction.description}</p></div>
                 <div className="grid grid-cols-2 gap-4">
                   <div className="p-5 bg-slate-50 rounded-3xl border border-slate-100"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Método</label><p className="font-bold text-slate-900">{selectedTransaction.paymentMethod || 'Não especificado'}</p></div>
                   <div className="p-5 bg-slate-50 rounded-3xl border border-slate-100"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Status</label><div className="mt-1">{getStatusBadge(selectedTransaction)}</div></div>
                 </div>
              </div>
            </div>
            <div className="p-8 border-t border-slate-100 grid grid-cols-2 gap-4">
              <button onClick={() => deleteTransaction(selectedTransaction.id)} className="py-4 bg-rose-50 text-rose-500 rounded-2xl font-black text-xs uppercase transition-all">Excluir</button>
              <button onClick={() => startEditTransaction(selectedTransaction)} className="py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase transition-all">Editar</button>
            </div>
          </div>
        </div>
      )}

      {/* Modals */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm animate-fadeIn no-print">
          <div className="bg-white rounded-[40px] w-full max-w-lg shadow-2xl overflow-hidden animate-scaleIn">
            <div className="px-8 py-6 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
              <h3 className="text-xl font-black text-slate-900">{editingTransaction ? 'Editar Lançamento' : 'Novo Lançamento'}</h3>
              <button onClick={closeAndResetModal} className="p-2 hover:bg-slate-200 rounded-xl transition-colors"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-slate-400"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg></button>
            </div>
            <div className="p-8 space-y-6 max-h-[80vh] overflow-y-auto">
              <div className="grid grid-cols-2 gap-2 p-1 bg-slate-100 rounded-2xl border border-slate-200">
                <button onClick={() => setFormType('EXPENSE')} className={`py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'EXPENSE' ? 'bg-rose-500 text-white' : 'text-slate-500'}`}>Saída</button>
                <button onClick={() => setFormType('INCOME')} className={`py-3 rounded-xl text-xs font-black uppercase transition-all ${formType === 'INCOME' ? 'bg-emerald-500 text-white' : 'text-slate-500'}`}>Entrada</button>
              </div>
              <div className="space-y-4">
                <input type="text" value={formDescription} onChange={(e) => setFormDescription(e.target.value)} placeholder="Descrição" className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" />
                <div className="grid grid-cols-2 gap-4">
                  <input type="number" value={formAmount} onChange={(e) => setFormAmount(e.target.value)} placeholder="Valor MZN" className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black" />
                  <input type="date" value={formDate} onChange={(e) => setFormDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <select value={formCategoryId} onChange={(e) => setFormCategoryId(e.target.value)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold">
                    <option value="">Categoria</option>
                    {categories.filter(c => c.type === formType).map(cat => <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>)}
                  </select>
                  <select value={formPaymentMethod} onChange={(e) => setFormPaymentMethod(e.target.value as PaymentProvider)} className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold">
                    <option value="CASH">Dinheiro</option>
                    <option value="BANK_TRANSFER">Transferência</option>
                    <option value="M-PESA">M-Pesa</option>
                    <option value="E-MOLA">e-Mola</option>
                  </select>
                </div>
              </div>
              <div className="pt-4 flex gap-3">
                <button onClick={closeAndResetModal} className="flex-1 py-5 bg-slate-100 rounded-2xl font-black text-xs uppercase transition-all">Cancelar</button>
                <button onClick={handleSaveTransaction} className="flex-1 py-5 bg-orange-500 text-white rounded-2xl font-black text-xs uppercase transition-all shadow-xl shadow-orange-500/20">Confirmar</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <CategoryManagerModal isOpen={isCategoryModalOpen} onClose={() => setIsCategoryModalOpen(false)} categories={categories} setCategories={setCategories} />
      <MobileMoneyModal isOpen={isMobileMoneyModalOpen} onClose={() => setIsMobileMoneyModalOpen(false)} amount={selectedTransaction?.amount || 0} description={selectedTransaction?.description || ''} onSuccess={handleMobileMoneySuccess} />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { AccountType, Transaction, Category, TransactionType, TransactionStatus, PaymentProvider } from '../types';
import { CategoryManagerModal } from './CategoryManagerModal';
import { MobileMoneyModal } from './MobileMoneyModal';
import { ReceiptTemplate } from './ReceiptTemplate';

const STORAGE_KEY = 'fintech_transactions_v1';
const CATEGORIES_STORAGE_KEY = 'fintech_categories_v1';

interface TransactionsPageProps {
  mode: AccountType;
  isModalOpen: boolean;
  onModalClose: () => void;
  onModalOpen: () => void;
  initialTransactionType: TransactionType | null;
}

export const TransactionsPage: React.FC<TransactionsPageProps> = ({ mode, isModalOpen, onModalClose, onModalOpen, initialTransactionType }) => {
  const [showFilters, setShowFilters] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  const [isMobileMoneyModalOpen, setIsMobileMoneyModalOpen] = useState(false);
  const [selectedTransaction, setSelectedTransaction] = useState<Transaction | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isPrintingReceipt, setIsPrintingReceipt] = useState(false);

  // Search & Filter States
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [filterStatus, setFilterStatus] = useState<TransactionStatus | 'ALL'>('ALL');

  // Form States
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formDescription, setFormDescription] = useState('');
  const [formAmount, setFormAmount] = useState<string>('');
  const [formDate, setFormDate] = useState(new Date().toISOString().split('T')[0]);
  const [formType, setFormType] = useState<TransactionType>('EXPENSE');
  const [formStatus, setFormStatus] = useState<TransactionStatus>('COMPLETED');
  const [formCategoryId, setFormCategoryId] = useState('');
  const [formNotes, setFormNotes] = useState('');
  const [formPaymentMethod, setFormPaymentMethod] = useState<PaymentProvider>('CASH');

  // Categories & Transactions State
  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem(CATEGORIES_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(transactions));
    if (selectedTransaction) {
      const updated = transactions.find(t => t.id === selectedTransaction.id);
      if (updated) setSelectedTransaction(updated);
    }
  }, [transactions]);

  const handlePrintReceipt = () => {
    if (isPrintingReceipt) return;
    setIsPrintingReceipt(true);
    // Delay mínimo apenas para garantir o estado do botão
    setTimeout(() => {
      window.print();
      setIsPrintingReceipt(false);
    }, 150);
  };

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = filterStatus === 'ALL' || t.status === filterStatus;
      const tDate = new Date(t.date).setHours(0,0,0,0);
      const matchesStart = !filterStartDate || tDate >= new Date(filterStartDate).setHours(0,0,0,0);
      const matchesEnd = !filterEndDate || tDate <= new Date(filterEndDate).setHours(0,0,0,0);
      return matchesSearch && matchesStatus && matchesStart && matchesEnd;
    });
  }, [transactions, searchTerm, filterStatus, filterStartDate, filterEndDate]);

  const handleExportCSV = () => {
    try {
      setIsExporting(true);
      const headers = ['Data', 'Descricao', 'Categoria', 'Tipo', 'Valor (MZN)', 'Status', 'Metodo'];
      const rows = filteredTransactions.map(t => [t.date, `"${t.description}"`, categories.find(c => c.id === t.categoryId)?.name || 'Outros', t.type, t.amount.toFixed(2), t.status, t.paymentMethod]);
      const csvContent = [headers.join(';'), ...rows.map(row => row.join(';'))].join('\n');
      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `FINTECH_Extrato.csv`;
      link.click();
    } finally {
      setIsExporting(false);
    }
  };

  const totals = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === 'INCOME') acc.income += curr.amount;
      else acc.expense += curr.amount;
      return acc;
    }, { income: 0, expense: 0 });
  }, [filteredTransactions]);

  const balance = totals.income - totals.expense;

  const closeAndResetModal = () => {
    onModalClose();
    setEditingTransaction(null);
    setFormDescription('');
    setFormAmount('');
    setFormDate(new Date().toISOString().split('T')[0]);
    setFormType('EXPENSE');
    setFormStatus('COMPLETED');
    setFormCategoryId('');
    setFormNotes('');
    setFormPaymentMethod('CASH');
  };

  const handleSaveTransaction = () => {
    if (!formDescription || !formAmount || !formCategoryId) {
      alert('Preencha os campos obrigatórios.');
      return;
    }
    const transactionData: Transaction = {
      id: editingTransaction?.id || Math.random().toString(36).substr(2, 9),
      amount: parseFloat(formAmount),
      description: formDescription,
      date: formDate,
      type: formType,
      status: formStatus,
      categoryId: formCategoryId,
      tenantId: 't1',
      notes: formNotes,
      paymentMethod: formPaymentMethod,
    };
    if (editingTransaction) setTransactions(transactions.map(t => t.id === editingTransaction.id ? transactionData : t));
    else setTransactions([transactionData, ...transactions]);
    closeAndResetModal();
  };

  const handleMobileMoneySuccess = (provider: PaymentProvider, number: string) => {
    if (selectedTransaction) {
      setTransactions(transactions.map(t => 
        t.id === selectedTransaction.id 
          ? { ...t, status: 'COMPLETED', paymentMethod: provider, mobileNumber: number, providerRef: Math.random().toString(36).substring(7).toUpperCase() } 
          : t
      ));
    }
  };

  const startEditTransaction = (t: Transaction) => {
    setEditingTransaction(t);
    setFormDescription(t.description);
    setFormAmount(t.amount.toString());
    setFormDate(t.date);
    setFormType(t.type);
    setFormStatus(t.status);
    setFormCategoryId(t.categoryId);
    setFormNotes(t.notes || '');
    setFormPaymentMethod(t.paymentMethod || 'CASH');
    onModalOpen();
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Eliminar este lançamento?')) {
      setTransactions(transactions.filter(t => t.id !== id));
      if (selectedTransaction?.id === id) setSelectedTransaction(null);
    }
  };

  const getStatusBadge = (t: Transaction, isLarge = false) => {
    const status = t.status;
    let colorClass = status === 'COMPLETED' ? "bg-emerald-50 text-emerald-600 border-emerald-100" : status === 'PENDING' ? "bg-amber-50 text-amber-600 border-amber-100" : "bg-rose-50 text-rose-600 border-rose-100";
    let label = status === 'COMPLETED' ? "Efetivado" : status === 'PENDING' ? "Pendente" : "Atrasado";
    return <span className={`${isLarge ? 'px-4 py-2 text-[12px]' : 'px-3 py-1.5 text-[10px]'} rounded-full font-black border uppercase ${colorClass}`}>{label}</span>;
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20 relative">
      {/* Receipt Template (Renderizado sempre que há uma seleção para estar pronto no DOM) */}
      {selectedTransaction && (
        <ReceiptTemplate 
          transaction={selectedTransaction} 
          category={categories.find(c => c.id === selectedTransaction.categoryId)}
          tenantName="FINTECH SaaS Moçambique" 
        />
      )}

      {/* Main UI */}
      <div className="no-print">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex-1 max-w-2xl w-full">
            <div className="flex items-center gap-3">
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Pesquisar registos..."
                className="w-full px-6 py-4 bg-white border border-slate-200 rounded-[24px] outline-none focus:ring-4 focus:ring-orange-500/10 transition-all font-medium text-slate-700 shadow-sm"
              />
              <button onClick={() => setShowFilters(!showFilters)} className={`p-4 rounded-[22px] border ${showFilters ? 'bg-orange-500 text-white border-orange-500' : 'bg-white border-slate-200 text-slate-500'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="21" x2="4" y1="4" y2="4"/><line x1="21" x2="4" y1="12" y2="12"/><line x1="21" x2="4" y1="20" y2="20"/><circle cx="7" cy="4" r="2"/><circle cx="17" cy="12" r="2"/><circle cx="7" cy="20" r="2"/></svg>
              </button>
            </div>
          </div>

          <div className="flex gap-3 w-full lg:w-auto">
            <button onClick={handleExportCSV} disabled={isExporting} className="px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-[22px] font-black text-xs uppercase tracking-widest">CSV</button>
            <button onClick={onModalOpen} className="flex-1 lg:flex-none bg-orange-500 text-white px-8 py-4 rounded-[22px] font-black text-xs uppercase tracking-widest shadow-lg shadow-orange-500/20 active:scale-95 transition-all">Novo Lançamento</button>
          </div>
        </div>

        {showFilters && (
          <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-xl grid grid-cols-1 md:grid-cols-3 gap-6 animate-slideDown mt-6">
            <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value as any)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none">
              <option value="ALL">Todos os Status</option>
              <option value="COMPLETED">Efetivado</option>
              <option value="PENDING">Pendente</option>
              <option value="OVERDUE">Atrasado</option>
            </select>
            <input type="date" value={filterStartDate} onChange={(e) => setFilterStartDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
            <input type="date" value={filterEndDate} onChange={(e) => setFilterEndDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
          </div>
        )}

        <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden mt-8">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                  <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Valor</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredTransactions.map((t) => (
                  <tr key={t.id} onClick={() => setSelectedTransaction(t)} className={`cursor-pointer transition-colors group ${selectedTransaction?.id === t.id ? 'bg-orange-50/50' : 'hover:bg-slate-50/50'}`}>
                    <td className="px-8 py-6 text-sm font-bold text-slate-400">{new Date(t.date).toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' })}</td>
                    <td className="px-8 py-6"><p className="text-sm font-black text-slate-900">{t.description}</p></td>
                    <td className="px-8 py-6"><span className="px-3 py-1.5 rounded-xl text-xs font-black bg-slate-100 text-slate-700">{categories.find(c => c.id === t.categoryId)?.name || 'Outros'}</span></td>
                    <td className="px-8 py-6">{getStatusBadge(t)}</td>
                    <td className={`px-8 py-6 text-base font-black text-right ${t.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>{t.amount.toLocaleString('pt-MZ')} MZN</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Detail Drawer */}
      {selectedTransaction && (
        <div className="fixed inset-0 z-[90] flex justify-end bg-slate-950/40 backdrop-blur-[2px] animate-fadeIn no-print" onClick={() => setSelectedTransaction(null)}>
          <div className="w-full max-w-md bg-white h-full shadow-2xl animate-slideLeft flex flex-col" onClick={(e) => e.stopPropagation()}>
            <div className="p-8 border-b border-slate-100 flex items-center justify-between">
              <div><h3 className="text-xl font-black text-slate-900">Detalhes</h3><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">#{selectedTransaction.id}</p></div>
              <button onClick={() => setSelectedTransaction(null)} className="p-3 hover:bg-slate-50 rounded-2xl border border-slate-100"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="text-center">
                <p className={`text-5xl font-black ${selectedTransaction.type === 'INCOME' ? 'text-emerald-500' : 'text-rose-500'}`}>{selectedTransaction.amount.toLocaleString('pt-MZ')} MZN</p>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Transação Registrada</p>
              </div>

              {selectedTransaction.type === 'INCOME' && (
                <button 
                  onClick={handlePrintReceipt}
                  disabled={isPrintingReceipt}
                  className={`w-full py-4 rounded-[24px] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl transition-all active:scale-95 ${isPrintingReceipt ? 'bg-slate-400 text-white cursor-not-allowed' : 'bg-slate-900 text-white hover:bg-black'}`}
                >
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
                  {isPrintingReceipt ? 'A preparar...' : 'Imprimir Recibo (PDF)'}
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Categorias Modal */}
      <CategoryManagerModal isOpen={isCategoryModalOpen} onClose={() => setIsCategoryModalOpen(false)} categories={categories} setCategories={setCategories} />

      {/* Mobile Money Modal */}
      <MobileMoneyModal isOpen={isMobileMoneyModalOpen} onClose={() => setIsMobileMoneyModalOpen(false)} amount={selectedTransaction?.amount || 0} description={selectedTransaction?.description || ''} onSuccess={handleMobileMoneySuccess} />
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';

const baseCategoryData = [
  { name: 'Infraestrutura', value: 4500, color: '#f97316' }, 
  { name: 'Operacional', value: 3000, color: '#1e293b' }, 
  { name: 'Marketing', value: 2000, color: '#94a3b8' }, 
  { name: 'Pessoal', value: 5000, color: '#fb923c' }, 
];

const highContrastColors = ['#000000', '#ffffff', '#ffff00', '#0000ff'];

const annualHistory = [
  { month: 'Junho', income: 60000, expense: 40000 },
  { month: 'Maio', income: 55000, expense: 42000 },
  { month: 'Abril', income: 50000, expense: 44000 },
  { month: 'Março', income: 45000, expense: 46000 },
  { month: 'Fevereiro', income: 42000, expense: 38000 },
  { month: 'Janeiro', income: 40000, expense: 35000 },
];

interface ReportsPageProps {
  onLoadAction: 'print' | null;
  onActionComplete: () => void;
  onBack: () => void;
}

export const ReportsPage: React.FC<ReportsPageProps> = ({ onLoadAction, onActionComplete, onBack }) => {
  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isPrinting, setIsPrinting] = useState(false);
  const [isHighContrast, setIsHighContrast] = useState(false);

  const handleExportPDF = useCallback(() => {
    if (isPrinting) return;
    setIsPrinting(true);
    // Tempo suficiente para os gráficos do Recharts estabilizarem sem animação
    setTimeout(() => {
      window.print();
      setIsPrinting(false);
      onActionComplete();
    }, 800);
  }, [isPrinting, onActionComplete]);

  useEffect(() => {
    if (onLoadAction === 'print') {
      handleExportPDF();
    }
  }, [onLoadAction, handleExportPDF]);

  const categoryData = baseCategoryData.map((item, index) => ({
    ...item,
    color: isHighContrast ? highContrastColors[index % highContrastColors.length] : item.color
  }));

  const handleExportCSV = async () => {
    try {
      setIsExportingCSV(true);
      const csvData = annualHistory.map(item => [
        item.month, item.income.toFixed(2), item.expense.toFixed(2), (item.income - item.expense).toFixed(2), 'FECHADO'
      ]);
      const headers = ['Mês', 'Receitas (MZN)', 'Despesas (MZN)', 'Saldo Líquido (MZN)', 'Status'];
      const csvContent = [headers.join(';'), ...csvData.map(row => row.join(';'))].join('\n');
      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `FINTECH_Financeiro.csv`;
      link.click();
    } finally {
      setIsExportingCSV(false);
    }
  };

  return (
    <article className={`space-y-8 animate-fadeIn pb-20 ${isHighContrast ? 'bg-white text-black' : ''}`}>
      <div className="no-print mb-4">
        <button onClick={onBack} className="group flex items-center gap-2 px-5 py-2.5 bg-white border border-slate-200 rounded-full shadow-sm hover:shadow-md transition-all">
          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-slate-400 group-hover:text-orange-500 transition-all"><path d="m15 18-6-6 6-6"/></svg>
          <span className="text-[11px] font-black uppercase tracking-widest text-slate-500">Voltar</span>
        </button>
      </div>

      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 no-print">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Relatórios</h2>
          <p className="text-slate-500 font-medium">Análise de dados financeiros.</p>
