        <div className="flex flex-wrap gap-3">
           <button onClick={handleExportCSV} disabled={isExportingCSV} className="px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3">CSV</button>
           <button onClick={handleExportPDF} className="px-6 py-4 bg-orange-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-orange-500/20 flex items-center gap-3 active:scale-95 transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
              {isPrinting ? 'A preparar...' : 'Imprimir PDF'}
           </button>
        </div>
      </header>

      {/* Layout de Impressão */}
      <div className="hidden print:block mb-8 border-b-2 border-slate-900 pb-6">
        <h1 className="text-3xl font-black text-slate-900 uppercase">FINTECH • Inteligência Financeira</h1>
        <p className="text-sm font-black mt-2">Data: {new Date().toLocaleDateString('pt-MZ')}</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <section className={`lg:col-span-2 p-10 rounded-[40px] shadow-sm border chart-container bg-white border-slate-100`}>
          <h3 className="text-lg font-black text-slate-900 mb-8">Composição de Despesas</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={categoryData} cx="50%" cy="50%" innerRadius={70} outerRadius={110} paddingAngle={5} dataKey="value" isAnimationActive={false}>
                  {categoryData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </section>

        <section className={`p-8 rounded-[40px] shadow-sm border bg-white border-slate-100`}>
           <h3 className="text-lg font-black text-slate-900 mb-8">Resumo Mensal</h3>
           <div className="space-y-4">
              {annualHistory.slice(0, 4).map((item, i) => (
                <div key={i} className="flex flex-col p-4 bg-slate-50 rounded-2xl border border-slate-100">
