      { id: '1', name: 'Supermercado Central', companyName: 'Grupo Central Lda', email: 'compras@central.mz', phone: '841234567', status: 'ACTIVE', totalRevenue: 125000, lastInteraction: '2023-10-15', tags: ['Varejo', 'VIP'] },
      { id: '2', name: 'Restaurante Marés', companyName: 'Marés Gastronomia', email: 'gerencia@mares.mz', phone: '829876543', status: 'ACTIVE', totalRevenue: 45000, lastInteraction: '2023-10-20', tags: ['Horeca'] },
      { id: '3', name: 'Tech Solutions', companyName: 'Tech Solutions SA', email: 'admin@techsol.mz', phone: '875551234', status: 'LEAD', totalRevenue: 0, lastInteraction: '2023-11-01', tags: ['Tecnologia'] }
    ];
  });

  const [transactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(TRANSACTIONS_STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [copied, setCopied] = useState(false);

  // Form States
  const [formName, setFormName] = useState('');
  const [formCompany, setFormCompany] = useState('');
  const [formEmail, setFormEmail] = useState('');
  const [formPhone, setFormPhone] = useState('');
  const [phoneError, setPhoneError] = useState<string | null>(null);
  const [emailError, setEmailError] = useState<string | null>(null);
  const [formTags, setFormTags] = useState('');

  useEffect(() => {
    localStorage.setItem(CLIENTS_STORAGE_KEY, JSON.stringify(clients));
  }, [clients]);

  // Reset copied state when drawer closes
  useEffect(() => {
    if (!selectedClient) setCopied(false);
  }, [selectedClient]);

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.companyName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value.replace(/\D/g, '');

    // Limite de 9 dígitos para MZ
    if (val.length > 9) return;

    setFormPhone(val);

    // Validação em Tempo Real
    if (val.length >= 2) {
      const prefix = val.substring(0, 2);
      const validPrefixes = ['82', '83', '84', '85', '86', '87'];

      if (!validPrefixes.includes(prefix)) {
        setPhoneError('Prefixo inválido. Use: 82, 83, 84, 85, 86 ou 87.');
      } else {
        setPhoneError(null);
      }
    } else {
      setPhoneError(null);
    }
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setFormEmail(val);

    // Regex simples para validação de e-mail
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (val && !emailRegex.test(val)) {
      setEmailError('Formato de e-mail inválido.');
    } else {
      setEmailError(null);
    }
  };

  const handleSaveClient = () => {
    // Validação final antes de salvar
    if (!formName || !formPhone) return;

    if (formPhone.length !== 9) {
      setPhoneError('O número deve ter 9 dígitos.');
      return;
    }

    if (phoneError || emailError) return;

    const newClient: Client = {
      id: Math.random().toString(36).substr(2, 9),
      name: formName,
      companyName: formCompany,
      email: formEmail,
      phone: formPhone,
      status: 'ACTIVE',
      totalRevenue: 0,
      lastInteraction: new Date().toISOString().split('T')[0],
      tags: formTags.split(',').map(t => t.trim()).filter(t => t)
    };

    setClients([newClient, ...clients]);
    closeModal();
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setFormName('');
    setFormCompany('');
    setFormEmail('');
    setFormPhone('');
    setPhoneError(null);
    setEmailError(null);
    setFormTags('');
  };

  const openWhatsApp = (phone: string) => {
    const cleanPhone = phone.replace(/\D/g, '');
    const number = cleanPhone.startsWith('258') ? cleanPhone : `258${cleanPhone}`;
    window.open(`https://wa.me/${number}`, '_blank');
  };

  const handleCopyPhone = (phone: string) => {
    navigator.clipboard.writeText(phone);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
